$ErrorActionPreference='Stop';$root=Split-Path -Parent $PSScriptRoot;$ff=Join-Path $root 'node_modules\ffmpeg-static\ffmpeg.exe';$dir=Join-Path $root 'video-fluid-en';$seg=Join-Path $dir 'segments';New-Item -ItemType Directory -Force $seg|Out-Null
for($i=1;$i-le 16;$i++){$img=Join-Path $dir ('{0:D2}.png'-f$i);$clip=Join-Path $seg ('{0:D2}.mp4'-f$i);&$ff -loglevel error -y -loop 1 -framerate 25 -i $img -t 7.5 -vf "scale=1440:900,zoompan=z='min(zoom+0.00012,1.015)':d=188:s=1440x900:fps=25,format=yuv420p" -an -c:v libx264 -preset medium -crf 20 $clip;if($LASTEXITCODE-ne 0){throw "Segment $i"}}
$list=Join-Path $seg 'concat.txt';$c=1..16|ForEach-Object{"file '$((Join-Path $seg ('{0:D2}.mp4'-f$_)).Replace('\','/'))'"};[IO.File]::WriteAllLines($list,$c,[Text.UTF8Encoding]::new($false));$silent=Join-Path $dir 'silent.mp4';&$ff -loglevel error -y -f concat -safe 0 -i $list -c copy $silent
$audio=Join-Path $dir 'narration.mp3';$out=Join-Path $root 'Waste2Cash_Full_Demo_EN_2min.mp4';&$ff -loglevel error -y -i $silent -i $audio -filter_complex "[1:a]atempo=1.065,apad,atrim=0:119.88,afade=t=out:st=118.8:d=1[a]" -map '0:v:0' -map '[a]' -t 119.88 -c:v copy -c:a aac -b:a 160k -movflags +faststart $out;if($LASTEXITCODE-ne 0){throw 'Final assembly failed'};Write-Output $out
